class UserRepositoryIntegrationTest {
    @Test
    fun `repository should fetch from api and cache to db`() = runTest {
        // Используем реальные, а не mock-объекты
        val api = RetrofitApi.create() // Real API (test endpoint)
        val db = Room.inMemoryDatabaseBuilder() // In-memory DB
        val repo = UserRepository(api, db)

        // Тестируем всю цепочку
        val user = repo.getUser("1")

        assertNotNull(user)
        assertEquals("1", user.id)
    }
}

@RunWith(AndroidJUnit4::class)
class UserDaoIntegrationTest {
    private lateinit var db: AppDatabase

    @Before
    fun setup() {
        // In-memory база для тестов
        db = Room.inMemoryDatabaseBuilder(
            ApplicationProvider.getApplicationContext(),
            AppDatabase::class.java
        ).build()
    }

    @Test
    fun `insert and retrieve user`() = runTest {
        // Arrange
        val user = User(id = "1", name = "John")
        val dao = db.userDao()

        // Act
        dao.insert(user)
        val retrieved = dao.getById("1")

        // Assert
        assertEquals(user, retrieved)
    }
}
